def _update_value(self, key, value):
    old_value = self.get(key)
    old_dict = old_value.feature if isinstance(old_value, Sequence) else old_value
    new_dict = value.feature if isinstance(value, Sequence) else value
    if key in self and isinstance(old_dict, dict) and isinstance(new_dict, dict):
        self._deep_merge_dicts(old_dict, new_dict)
    else:
        self[key] = value

@staticmethod
def _deep_merge_dicts(old_dict: dict, new_dict: dict) -> None:
    for key, value in new_dict.items():
        old_value = old_dict.get(key)
        old_sub_dict = old_value.feature if isinstance(old_value, Sequence) else old_value
        new_sub_dict = value.feature if isinstance(value, Sequence) else value
        if key in old_dict and isinstance(old_sub_dict, dict) and isinstance(new_sub_dict, dict):
            Features._deep_merge_dicts(old_sub_dict, new_sub_dict)
        else:
            old_dict[key] = value

