def test_update_with_nested_dict_deep_merges(self):
    features = Features({"a": {"x": Value("int32"), "y": Value("string")}, "b": Value("int64")})
    features.update({"a": {"z": Value("float32")}, "c": Value("bool")})
    self.assertEqual(
        features,
        Features(
            {
                "a": {"x": Value("int32"), "y": Value("string"), "z": Value("float32")},
                "b": Value("int64"),
                "c": Value("bool"),
            }
        ),
    )

def test_update_with_nested_sequence_deep_merges(self):
    features = Features({"a": Sequence({"x": Value("int32"), "y": Value("string")})})
    features.update({"a": Sequence({"z": Value("float32")})})
    self.assertEqual(
        features,
        Features({"a": Sequence({"x": Value("int32"), "y": Value("string"), "z": Value("float32")})}),
    )

def test_update_with_kwds_deep_merges(self):
    features = Features({"a": {"x": Value("int32")}})
    features.update(a={"y": Value("string")})
    self.assertEqual(features, Features({"a": {"x": Value("int32"), "y": Value("string")}}))

